# app/helpers/profile_helper.rb
module ProfileHelper
  # Renders user profile descriptions with safe HTML formatting.
  # Uses a whitelist approach to allow specific HTML tags and attributes
  # while stripping all potentially dangerous content.
  def render_profile_description(content)
    return "" if content.blank?

    # Sanitize the content, allowing only safe HTML tags and attributes
    allowed_tags = %w[
      p br h1 h2 h3 h4 h5 h6
      strong em b i u s strike
      ul ol li
      a blockquote pre code
      img hr span div
      table thead tbody tr th td
    ]

    allowed_attributes = %w[
      href src alt title class id
      target rel width height
      colspan rowspan
    ]

    sanitized_content = sanitize(
      content,
      tags: allowed_tags,
      attributes: allowed_attributes
    )

    # Ensure links open safely and don't allow javascript: URLs
    sanitized_content = sanitized_content.gsub(/href\s*=\s*["']javascript:/i, 'href="')
    sanitized_content = sanitized_content.gsub(/<a\s/, '<a rel="nofollow noopener noreferrer" ')

    sanitized_content.html_safe
  end

